using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
using System.Collections.Generic;
public class Script
{
    public static object Main()
    {
        var dm = DataManager.Instance;
        if (dm == null) return "DataManager.Instance is null";
        var sb = new System.Text.StringBuilder();
        var field = typeof(DataManager).GetField("_npcDataDict", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
        if (field == null) {
            var fields = typeof(DataManager).GetFields(System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            foreach (var f in fields) {
                if (f.Name.ToLower().Contains("npc")) sb.AppendLine("field: " + f.Name + " type=" + f.FieldType.Name);
            }
            return sb.ToString();
        }
        var dict = field.GetValue(dm);
        sb.AppendLine("NPC dict type: " + dict?.GetType().Name);
        return sb.ToString();
    }
}
